import React, { useState, useEffect } from 'react';
import './css/constitution.css';

const constitutionData = [
  {
    title: { ky: "БИРИНЧИ БӨЛҮК. КОНСТИТУЦИЯЛЫК ТҮЗҮЛҮШТҮН НЕГИЗДЕРИ", ru: "РАЗДЕЛ ПЕРВЫЙ. ОСНОВЫ КОНСТИТУЦИОННОГО СТРОЯ" },
    articles: [
      { id: 1, title: { ky: "1-берене", ru: "Статья 1" }, content: { ky: "1. Кыргыз Республикасы көз каранды эмес, эгемендүү, демократиялык, укуктук, дүйнөлүк, социалдык, унитардык мамлекет.", ru: "1. Кыргызская Республика является независимым, суверенным, демократическим, правовым, светским, социальным, унитарным государством." } },
      { id: 2, title: { ky: "2-берене", ru: "Статья 2" }, content: { ky: "1. Кыргызстандын эли эгемендүүлүктүн ээси жана мамлекеттик бийликтин жалгыз булагы. 2. Эл бийликти түздөн-түз референдумдар, шайлоолор аркылуу, ошондой эле мамлекеттик органдар жана жергиликтүү өзүн-өзү башкаруу органдарынын тутуму аркылуу ишке ашырат.", ru: "1. Народ Кыргызстана является носителем суверенитета и единственным источником государственной власти. 2. Народ осуществляет свою власть непосредственно через референдумы, выборы, а также через систему государственных органов и органов местного самоуправления." } },
      { id: 3, title: { ky: "3-берене", ru: "Статья 3" }, content: { ky: "1. Кыргыз Республикасында мамлекеттик бийлик мыйзам чыгаруу, аткаруу жана сот бийликтерине бөлүү принцибине негизделет. 2. Мыйзам чыгаруу, аткаруу жана сот бийликтеринин органдары өз ара аракеттенишет жана ыйгарым укуктарынын чегинде көз каранды эмес.", ru: "1. Государственная власть в Кыргызской Республике основывается на принципах разделения властей на законодательную, исполнительную и судебную. 2. Органы законодательной, исполнительной и судебной власти взаимодействуют друг с другом и самостоятельны в пределах своих полномочий." } },
      { id: 4, title: { ky: "4-берене", ru: "Статья 4" }, content: { ky: "1. Кыргыз Республикасында саясий ар түрдүүлүк жана көп партиялуулук таанылат. 2. Мамлекеттик жана муниципалдык органдардын саясий партиялар менен биригишине тыюу салынат.", ru: "1. В Кыргызской Республике признается политическое многообразие и многопартийность. 2. Запрещается слияние государственных и муниципальных органов с политическими партиями." } },
      { id: 5, title: { ky: "5-берене", ru: "Статья 5" }, content: { ky: "1. Мамлекет жана анын органдары бүтүндөй коомго кызмат кылат, анын айрым бөлүгүнө эмес. 2. Кыргыз Республикасында адамдын укуктарын жана эркиндиктерин тарылтуучу мыйзамдарды кабыл алууга жол берилбейт.", ru: "1. Государство и его органы служат всему обществу, а не какой-то его части. 2. В Кыргызской Республике не допускается принятие законов, сужающих права и свободы человека." } },
      { id: 6, title: { ky: "6-берене", ru: "Статья 6" }, content: { ky: "1. Конституция жогорку юридикалык күчкө ээ жана Кыргыз Республикасынын бүткүл аймагында түздөн-түз колдонулат. 2. Мыйзамдар жана башка ченемдик укуктук актылар Конституцияга каршы келүүгө тийиш эмес.", ru: "1. Конституция имеет высшую юридическую силу и прямое действие на всей территории Кыргызской Республики. 2. Законы и иные нормативные правовые акты не должны противоречить Конституции." } },
      { id: 7, title: { ky: "7-берене", ru: "Статья 7" }, content: { ky: "1. Элдик Курултай - коомдук-өкүлчүлүк чогулуш, ал коомдук өнүгүү маселелерин талкуулайт жана сунуштарды иштеп чыгат.", ru: "1. Народный Курултай - общественно-представительное собрание, которое обсуждает вопросы общественного развития и вырабатывает рекомендации." } },
      { id: 8, title: { ky: "8-берене", ru: "Статья 8" }, content: { ky: "1. Кыргыз Республикасында эч кандай дин мамлекеттик же милдеттүү дин катары белгилене албайт. 2. Диний бирикмелер мамлекеттен бөлүнгөн.", ru: "1. В Кыргызской Республике никакая религия не может устанавливаться в качестве государственной или обязательной. 2. Религиозные объединения отделены от государства." } },
      { id: 9, title: { ky: "9-берене", ru: "Статья 9" }, content: { ky: "1. Кыргыз Республикасынын экспансия, агрессия жана аймактык талап кылуу максаттары жок. 2. Тышкы саясат тынч кошо жашоо принциптерине негизделет.", ru: "1. Кыргызская Республика не имеет целей экспансии, агрессии и территориальных притязаний. 2. Внешняя политика строится на принципах мирного сосуществования." } },
      { id: 10, title: { ky: "10-берене", ru: "Статья 10" }, content: { ky: "1. Көркөм каражаттардын маалымат каражаттары эркин жана мыйзамга ылайык иш алып барат. 2. Цензурага тыюу салынат.", ru: "1. Средства массовой информации свободны и работают в соответствии с законом. 2. Цензура запрещается." } },
      { id: 11, title: { ky: "11-берене", ru: "Статья 11" }, content: { ky: "1. Мамлекет укук тартибин жана жарандардын коопсуздугун камсыз кылат. 2. Куралдуу Күчтөр эгемендүүлүктү жана аймактык бүтүндүктү коргойт.", ru: "1. Государство обеспечивает правопорядок и безопасность граждан. 2. Вооруженные Силы защищают суверенитет и территориальную целостность." } },
      { id: 12, title: { ky: "12-берене", ru: "Статья 12" }, content: { ky: "1. Кыргыз тили - мамлекеттик тил. 2. Орус тили - расмий тил. 3. Мамлекет Кыргызстандын элдеринин тилдерин өнүктүрүү үчүн шарттарды түзөт.", ru: "1. Кыргызский язык - государственный язык. 2. Русский язык - официальный язык. 3. Государство создает условия для развития языков народов Кыргызстана." } },
      { id: 13, title: { ky: "13-берене", ru: "Статья 13" }, content: { ky: "1. Кыргыз Республикасынын мамлекеттик символдору бар: Туу, Герб жана Гимн. 2. Символдордун сыпаттамасы жана колдонуу тартиби мыйзам менен белгиленет.", ru: "1. Кыргызская Республика имеет государственные символы: Флаг, Герб и Гимн. 2. Описание и порядок использования символов устанавливаются законом." } },
      { id: 14, title: { ky: "14-берене", ru: "Статья 14" }, content: { ky: "1. Мамлекет Кыргызстандын элдеринин маданиятын, салттарын жана адаттарын өнүктүрүү үчүн шарттарды түзөт. 2. Маданий мурас мамлекет тарабынан корголот.", ru: "1. Государство создает условия для развития культуры, традиций и обычаев народов Кыргызстана. 2. Культурное наследие охраняется государством." } },
      { id: 15, title: { ky: "2-БАП. 15-берене", ru: "ГЛАВА II. Статья 15" }, content: { ky: "1. Кыргыз Республикасында жеке, мамлекеттик, муниципалдык жана менчиктин башка түрлөрү таанылат. 2. Мамлекет менчиктин бардык түрлөрүн тең коргоого кепилдик берет.", ru: "1. В Кыргызской Республике признаются частная, государственная, муниципальная и иные формы собственности. 2. Государство гарантирует равную защиту всех форм собственности." } },
      { id: 16, title: { ky: "16-берене", ru: "Статья 16" }, content: { ky: "1. Жер, кен байлыктар, суулар, өсүмдүк жана айбанат дүйнөсү Кыргыз Республикасынын менчиги болуп саналат. 2. Мамлекет табигый ресурстарды элдин кызыкчылыгында башкарат.", ru: "1. Земля, недра, воды, растительный и животный мир являются собственностью Кыргызской Республики. 2. Государство управляет природными ресурсами в интересах народа." } },
      { id: 17, title: { ky: "17-берене", ru: "Статья 17" }, content: { ky: "1. Мамлекет жарандардын жагымдуу экологияга болгон укуктарын коргойт. 2. Табигый чөйрөгө зыян келтирген адамдар мыйзам боюнча жоопко тартылат.", ru: "1. Государство защищает права граждан на благоприятную экологию. 2. Лица, причинившие вред окружающей среде, несут ответственность по закону." } },
      { id: 18, title: { ky: "18-берене", ru: "Статья 18" }, content: { ky: "1. Мамлекет тарыхый жана маданий мурасты коргойт. 2. Тарыхый жана маданий эстеликтерди бузгандар мыйзам боюнча жоопкерчиликке тартылат.", ru: "1. Государство охраняет историческое и культурное наследие. 2. Лица, нарушающие исторические и культурные памятники, привлекаются к ответственности по закону." } },
      { id: 19, title: { ky: "19-берене", ru: "Статья 19" }, content: { ky: "1. Үй-бүлө - коомдун негизи. Мамлекет үй-бүлө институтун колдойт. 2. Ата-энелер балдарын тарбиялоого милдеттүү.", ru: "1. Семья - основа общества. Государство поддерживает институт семьи. 2. Родители обязаны воспитывать своих детей." } },
      { id: 20, title: { ky: "20-берене", ru: "Статья 20" }, content: { ky: "1. Адамдын укуктары Конституция жана мыйзамдар менен гана чектелиши мүмкүн. 2. Адамдын укуктарын чектөө конституциялык түзүлүштү, коомдук тартипти, адамдардын укуктарын жана эркиндиктерин коргоо максатында гана киргизилет.", ru: "1. Права человека могут быть ограничены только Конституцией и законами. 2. Ограничения прав человека вводятся только в целях защиты конституционного строя, общественного порядка, прав и свобод человека." } },
      { id: 21, title: { ky: "21-берене", ru: "Статья 21" }, content: { ky: "1. Мамлекет эл аралык милдеттенмелердин аткарылышына кепилдик берет. 2. Кыргыз Республикасынын эл аралык келишимдери мыйзамдардан артыкчылыкка ээ.", ru: "1. Государство гарантирует исполнение международных обязательств. 2. Международные договоры Кыргызской Республики имеют приоритет над законами." } },
      { id: 22, title: { ky: "22-берене", ru: "Статья 22" }, content: { ky: "1. Ченемдик укуктук актылар жарыялангандан кийин гана күчүнө кирет. 2. Жарыяланбаган мыйзамдар жана башка ченемдик укуктук актылар колдонулбайт.", ru: "1. Нормативные правовые акты вступают в силу только после опубликования. 2. Неопубликованные законы и иные нормативные правовые акты не применяются." } }
    ]
  },
  {
    title: { ky: "ЭКИНЧИ БӨЛҮК. АДАМДЫН УКУКТАРЫ ЖАНА ЭРКИНДИКТЕРИ", ru: "РАЗДЕЛ ВТОРОЙ. ПРАВА И СВОБОДЫ ЧЕЛОВЕКА" },
    articles: [
      { id: 23, title: { ky: "1-БАП. 23-берене", ru: "ГЛАВА I. Статья 23" }, content: { ky: "1. Адамдын укуктары эликтүү эмес жана ар бир адамга төрөлгөндөн тарта таандык. 2. Адам укуктары мамлекет тарабынан таанылып, сакталышы керек.", ru: "1. Права человека неотчуждаемы и принадлежат каждому от рождения. 2. Права человека должны признаваться и соблюдаться государством." } },
      { id: 24, title: { ky: "24-берене", ru: "Статья 24" }, content: { ky: "1. Кыргыз Республикасында баары мыйзамдын жана соттун алдында тең. Дискриминацияга тыюу салынат. 2. Эч ким жынысына, расасына, улутуна, тилине, динине, саясий ишенимине жараша кемсинтиле албайт.", ru: "1. В Кыргызской Республике все равны перед законом и судом. Дискриминация запрещена. 2. Никто не может подвергаться дискриминации по признаку пола, расы, национальности, языка, религии, политических убеждений." } },
      { id: 25, title: { ky: "25-берене", ru: "Статья 25" }, content: { ky: "1. Ар бир адамдын жашоого укугу бар. Өлүм жазасына тыюу салынат. 2. Ар бир адамдын денесине жана психикасына зордук-зомбулук көрсөтүлүүдөн коргонууга укугу бар.", ru: "1. Каждый имеет право на жизнь. Смертная казнь запрещена. 2. Каждый имеет право на защиту от насилия над личностью и психикой." } },
      { id: 26, title: { ky: "26-берене", ru: "Статья 26" }, content: { ky: "1. Ар бир адамдын жеке эркиндиги жана кол тийбестиги укугу бар. 2. Эч ким мыйзамсыз камакка алына же кармала албайт.", ru: "1. Каждый имеет право на личную свободу и неприкосновенность. 2. Никто не может быть арестован или задержан без законного основания." } },
      { id: 27, title: { ky: "27-берене", ru: "Статья 27" }, content: { ky: "1. Эч ким азаптоого же универсалдуу эмес мамилеге дуушар боло албайт. 2. Адамдарга медициналык же илимий эксперименттерди жүргүзүүгө алардын макулдугусуз жол берилбейт.", ru: "1. Никто не может быть подвергнут пыткам или унижающему достоинство обращению. 2. Медицинские или научные эксперименты над людьми не допускаются без их согласия." } },
      { id: 28, title: { ky: "28-берене", ru: "Статья 28" }, content: { ky: "1. Ар бир адамдын ар-намысын, кадыр-баркын жана жакшы ысымын коргоого укугу бар. 2. Эч кимдин ар-намысына жана кадыр-баркына шек келтирүүгө жол берилбейт.", ru: "1. Каждый имеет право на защиту чести, достоинства и доброго имени. 2. Не допускается посягательство на честь и достоинство человека." } },
      { id: 29, title: { ky: "29-берене", ru: "Статья 29" }, content: { ky: "1. Ар бир адамдын кат жазышуу, телефон сүйлөшүүлөрү, почта, телеграф жана башка байланыштардын сырын сактоого укугу бар. 2. Бул укукту чектөө мыйзамда каралган учурларда гана жол берилет.", ru: "1. Каждый имеет право на тайну переписки, телефонных переговоров, почтовых, телеграфных и иных сообщений. 2. Ограничение этого права допускается только в случаях, предусмотренных законом." } },
      { id: 30, title: { ky: "30-берене", ru: "Статья 30" }, content: { ky: "1. Турак жай кол тийбес. Тинтүүгө мыйзамда белгиленген тартипте гана жол берилет. 2. Эч ким өзүнүн турак жайына эркине каршы кирүүдөн коргонууга укугу бар.", ru: "1. Жилище неприкосновенно. Обыск допускается только в порядке, установленном законом. 2. Каждый имеет право на защиту от проникновения в его жилище против его воли." } },
      { id: 31, title: { ky: "31-берене", ru: "Статья 31" }, content: { ky: "1. Ар бир адамдын эркин жүрүү жана жашаган жерин тандоо укугу бар. 2. Кыргыз Республикасынын ар бир жараны республиканын аймагында эркин жүрүүгө жана жашаган жерин тандоого укуктуу.", ru: "1. Каждый имеет право на свободу передвижения и выбор места жительства. 2. Каждый гражданин Кыргызской Республики имеет право свободно передвигаться и выбирать место жительства на территории республики." } },
      { id: 32, title: { ky: "32-берене", ru: "Статья 32" }, content: { ky: "1. Ар бир адамга ар-ожун жана дин тутуу эркиндиги кепилденет. 2. Эч ким өзүнүн динин билдирүүгө же билдирбөөгө мажбурлана албайт.", ru: "1. Каждому гарантируется свобода совести и вероисповедания. 2. Никто не может быть принужден к выражению своих религиозных убеждений или отказу от них." } },
      { id: 33, title: { ky: "33-берене", ru: "Статья 33" }, content: { ky: "1. Ар бир адамдын ой жүгүртүү жана пикир билдирүү эркиндиги укугу бар. 2. Эч ким өзүнүн ой-пикирлери үчүн куугунтуктала албайт.", ru: "1. Каждый имеет право на свободу мысли и мнения. 2. Никто не может быть преследован за свои убеждения." } },
      { id: 34, title: { ky: "34-берене", ru: "Статья 34" }, content: { ky: "1. Ар бир адам мамлекеттик органдардын ишмердүүлүгү жөнүндө маалымат алууга укуктуу. 2. Мамлекеттик органдар өздөрүнүн ишмердүүлүгү тууралуу маалыматты камсыз кылууга милдеттүү.", ru: "1. Каждый имеет право на получение информации о деятельности государственных органов. 2. Государственные органы обязаны обеспечивать доступ к информации о своей деятельности." } },
      { id: 35, title: { ky: "35-берене", ru: "Статья 35" }, content: { ky: "1. Ар бир жаранын бийлик органдарына кайрылууга укугу бар. 2. Мамлекеттик органдар жана жергиликтүү өзүн-өзү башкаруу органдары кайрылууларды кароого жана мыйзамда белгиленген мөөнөттө жооп берүүгө милдеттүү.", ru: "1. Каждый гражданин имеет право на обращение в органы власти. 2. Государственные органы и органы местного самоуправления обязаны рассматривать обращения и давать ответ в установленный законом срок." } },
      { id: 36, title: { ky: "36-берене", ru: "Статья 36" }, content: { ky: "1. Жарандардын бирикмелерге жана партияларга биригүүгө укугу бар. 2. Ар бир адам өз кызыкчылыктарын коргоо үчүн коомдук бирикмелерди түзүүгө укуктуу.", ru: "1. Граждане имеют право на объединение в союзы и партии. 2. Каждый имеет право создавать общественные объединения для защиты своих интересов." } },
      { id: 37, title: { ky: "37-берене", ru: "Статья 37" }, content: { ky: "1. Жарандардын шайлоого шайланууга жана шайланууга укугу бар. 2. Кыргыз Республикасынын жарандары шайлоо жана шайлануу укугуна ээ.", ru: "1. Граждане имеют право избирать и быть избранными. 2. Граждане Кыргызской Республики имеют право избирать и быть избранными." } },
      { id: 38, title: { ky: "38-берене", ru: "Статья 38" }, content: { ky: "1. Жарандык - бул адам менен мамлекеттин ортосундагы укуктук байланыш. 2. Кыргыз Республикасынын жараны өзүнүн жарандыгынан ажыратыла албайт.", ru: "1. Гражданство - это правовая связь человека с государством. 2. Гражданин Кыргызской Республики не может быть лишен своего гражданства." } },
      { id: 39, title: { ky: "39-берене", ru: "Статья 39" }, content: { ky: "1. Ар бир адамдын тынч чогулуштардын эркиндиги укугу бар. 2. Тынч жана куралсыз чогулуштарды өткөрүү үчүн алдын ала уруксат талап кылынбайт.", ru: "1. Каждый имеет право на свободу мирных собраний. 2. Для проведения мирных и безоружных собраний предварительное разрешение не требуется." } },
      { id: 40, title: { ky: "40-берене", ru: "Статья 40" }, content: { ky: "1. Ар бир адамдын жеке менчикке укугу бар. 2. Эч ким өзүнүн менчигинен мыйзамсыз ажыратыла албайт.", ru: "1. Каждый имеет право на частную собственность. 2. Никто не может быть лишен своей собственности незаконно." } },
      { id: 41, title: { ky: "41-берене", ru: "Статья 41" }, content: { ky: "1. Экономикалык эркиндик кепилденет. Монополия мыйзам менен чектелет. 2. Мамлекет намыстык атаандаштыкты колдойт.", ru: "1. Экономическая свобода гарантируется. Монополия ограничивается законом. 2. Государство поддерживает добросовестную конкуренцию." } },
      { id: 42, title: { ky: "42-берене", ru: "Статья 42" }, content: { ky: "1. Ар бир адамдын эмгектенүүгө жана акыйкат эмгек шарттарына укугу бар. 2. Ар бир адам өзүнүн эмгектенүү жөндөмдүүлүгүн эркин тандоо укугуна ээ.", ru: "1. Каждый имеет право на труд и справедливые условия труда. 2. Каждый имеет право свободно распоряжаться своими способностями к труду." } },
      { id: 43, title: { ky: "43-берене", ru: "Статья 43" }, content: { ky: "1. Ар бир адамдын ден соолугун сактоого жана медициналык жардам алууга укугу бар. 2. Мамлекеттик саламаттык сактоо мекемелеринде медициналык жардам акысыз көрсөтүлөт.", ru: "1. Каждый имеет право на охрану здоровья и медицинскую помощь. 2. В государственных учреждениях здравоохранения медицинская помощь оказывается бесплатно." } },
      { id: 44, title: { ky: "44-берене", ru: "Статья 44" }, content: { ky: "1. Картайганда, оорулууда, эмгекке жарамдуулугун жоготкондо социалдык камсыздандырууга кепилдик берилет. 2. Мамлекет социалдык камсыздандыруунун мамлекеттик тутумун өнүктүрөт.", ru: "1. Гарантируется социальное обеспечение в старости, при болезни, инвалидности. 2. Государство развивает государственную систему социального обеспечения." } },
      { id: 45, title: { ky: "45-берене", ru: "Статья 45" }, content: { ky: "1. Ар бир адамдын турак жайга укугу бар. Мамлекет турак жай алууга көмөктөшөт. 2. Кедей жана муктаж үй-бүлөлөргө мамлекеттик турак жай фондунан турак жай берилет.", ru: "1. Каждый имеет право на жилище. Государство содействует получению жилья. 2. Малоимущим и нуждающимся семьям предоставляется жилье из государственного жилищного фонда." } },
      { id: 46, title: { ky: "46-берене", ru: "Статья 46" }, content: { ky: "1. Ар бир адамдын акысыз мектепте окууга укугу бар. 2. Мамлекеттик мектептерде негизги жалпы билим берүү акысыз.", ru: "1. Каждый имеет право на бесплатное школьное образование. 2. В государственных школах основное общее образование бесплатно." } },
      { id: 47, title: { ky: "47-берене", ru: "Статья 47" }, content: { ky: "1. Үй-бүлө, аталык, энелик жана балалык - мамлекеттин камкордугунун предмети. 2. Мамлекет балдары бар үй-бүлөлөргө социалдык колдоо көрсөтөт.", ru: "1. Семья, отцовство, материнство и детство - предмет заботы государства. 2. Государство оказывает социальную поддержку семьям с детьми." } },
      { id: 48, title: { ky: "48-берене", ru: "Статья 48" }, content: { ky: "1. Мамлекет жарандардын эс алуусу жана эс алышы үчүн шарттарды түзөт. 2. Иштегендерге жумалык эс алуу жана майрам күндөрү кепилденет.", ru: "1. Государство создает условия для досуга и отдыха граждан. 2. Работающим гарантируется еженедельный отдых и праздничные дни." } },
      { id: 49, title: { ky: "49-берене", ru: "Статья 49" }, content: { ky: "1. Ар бир адамга соттук коргоо укугу кепилденет. 2. Ар бир адам өзүнүн укуктарын жана эркиндиктерин сот аркылуу коргоого укуктуу.", ru: "1. Каждому гарантируется право на судебную защиту. 2. Каждый имеет право защищать свои права и свободы в суде." } },
      { id: 50, title: { ky: "50-берене", ru: "Статья 50" }, content: { ky: "1. Кыргыз Республикасындагы чет элдиктер жарандар менен бирдей укуктарга ээ. 2. Чет элдиктер мыйзамда белгиленген учурларды кошпогондо, жарандар менен бирдей укуктарды пайдаланышат.", ru: "1. Иностранцы в Кыргызской Республике обладают правами наравне с гражданами. 2. Иностранцы пользуются правами наравне с гражданами, за исключением случаев, установленных законом." } },
      { id: 51, title: { ky: "51-берене", ru: "Статья 51" }, content: { ky: "1. Кыргыз Республикасы өзүнүн жарандарын өлкөдөн тышкары жерлерде коргойт. 2. Кыргыз Республикасы өзүнүн жарандарына дипломатиялык жана консулдук коргоону камсыз кылат.", ru: "1. Кыргызская Республика защищает своих граждан за пределами страны. 2. Кыргызская Республика обеспечивает своим гражданам дипломатическую и консульскую защиту." } },
      { id: 52, title: { ky: "52-берене", ru: "Статья 52" }, content: { ky: "1. Жарандар мыйзамда белгиленген тартипте салык төлөөгө милдеттүү. 2. Салыктар жана жыйымдар мыйзам негизинде гана белгиленет.", ru: "1. Граждане обязаны платить налоги в порядке, установленном законом. 2. Налоги и сборы устанавливаются только на основании закона." } },
      { id: 53, title: { ky: "53-берене", ru: "Статья 53" }, content: { ky: "1. Мекенди коргоо - жарандын ыйык милдети жана милдети. 2. Кыргыз Республикасынын жараны мыйзамда белгиленген тартипте аскердик кызматты өтөөгө милдеттүү.", ru: "1. Защита Отечества - священный долг и обязанность гражданина. 2. Гражданин Кыргызской Республики обязан проходить военную службу в порядке, установленном законом." } },
      { id: 54, title: { ky: "54-берене", ru: "Статья 54" }, content: { ky: "1. Жарандар жаратылышты жана айлана-чөйрөнү сактоого милдеттүү. 2. Ар бир адам табигый чөйрөгө этияттык менен мамиле кылууга милдеттүү.", ru: "1. Граждане обязаны беречь природу и окружающую среду. 2. Каждый обязан бережно относиться к природной среде." } },
      { id: 55, title: { ky: "6-БАП. 55-берене", ru: "ГЛАВА VI. Статья 55" }, content: { ky: "1. Кыргыз Республикасында адамдын укуктары жана эркиндиктери таанылат жана кепилденет. 2. Адамдын укуктары жана эркиндиктери конституциялык түзүлүштү, адеп-ахлакты, ден соолукту, укуктарды жана башка адамдардын эркиндиктерин коргоо үчүн гана чектелиши мүмкүн.", ru: "1. В Кыргызской Республике признаются и гарантируются права и свободы человека. 2. Права и свободы человека могут быть ограничены только для защиты конституционного строя, нравственности, здоровья, прав и свобод других лиц." } },
      { id: 56, title: { ky: "56-берене", ru: "Статья 56" }, content: { ky: "1. Мамлекет укуктарды коргоону бардык жеткиликтүү жолдор менен камсыз кылат. 2. Укуктарды жана эркиндиктерди коргоо мамлекеттин милдети.", ru: "1. Государство обеспечивает защиту прав всеми доступными способами. 2. Защита прав и свобод - обязанность государства." } },
      { id: 57, title: { ky: "57-берене", ru: "Статья 57" }, content: { ky: "1. Ар бир адам күнөөсү сот тарабынан далилденгенге чейин күнөөсүз деп эсептелет. 2. Күнөөлүүлүгүн далилдөө милдети айыпталуучуга жүктөлбөйт.", ru: "1. Каждый считается невиновным, пока вина не доказана судом. 2. Обязанность доказывания вины не возлагается на обвиняемого." } },
      { id: 58, title: { ky: "58-берене", ru: "Статья 58" }, content: { ky: "1. Эч ким бир эле кылмыш үчүн эки жолу соттоло албайт. 2. Эч ким бир эле укук бузуу үчүн кайрадан жоопко тартыла албайт.", ru: "1. Никто не может быть судим дважды за одно и то же преступление. 2. Никто не может быть повторно привлечен к ответственности за одно и то же правонарушение." } },
      { id: 59, title: { ky: "59-берене", ru: "Статья 59" }, content: { ky: "1. Ар бир адам квалификациялуу юридикалык жардам алууга укуктуу. 2. Мыйзамда каралган учурларда юридикалык жардам акысыз көрсөтүлөт.", ru: "1. Каждый имеет право на квалифицированную юридическую помощь. 2. В предусмотренных законом случаях юридическая помощь оказывается бесплатно." } },
      { id: 60, title: { ky: "60-берене", ru: "Статья 60" }, content: { ky: "1. Жоопкерчиликти оордоткон мыйзам артка кайтуу күчүнө ээ эмес. 2. Эч ким кылмыш жасалган учурда мыйзамда каралбаган кылмыш үчүн жоопко тартыла албайт.", ru: "1. Закон, отягчающий ответственность, обратной силы не имеет. 2. Никто не может нести ответственность за преступление, не предусмотренное законом на момент его совершения." } },
      { id: 61, title: { ky: "61-берене", ru: "Статья 61" }, content: { ky: "1. Ар бир адамга мамлекет тарабынан келтирилген зыяндын ордун толтуруу укугу кепилденет. 2. Мамлекеттик органдардын мыйзамсыз аракеттеринен келтирилген зыяндын ордун толтурулат.", ru: "1. Каждому гарантируется право на возмещение вреда, причиненного государством. 2. Вред, причиненный незаконными действиями государственных органов, подлежит возмещению." } },
      { id: 62, title: { ky: "62-берене", ru: "Статья 62" }, content: { ky: "1. Эч ким өзүнө каршы күбөлөндүрүүгө милдеттүү эмес. 2. Эч ким өзүнүн жакын туугандарына каршы күбөлөндүрүүгө мажбурлана албайт.", ru: "1. Никто не обязан свидетельствовать против самого себя. 2. Никто не может быть принужден к даче показаний против своих близких родственников." } },
      { id: 63, title: { ky: "63-берене", ru: "Статья 63" }, content: { ky: "1. Ар бир адамдын акыйкат соттук териштирүүгө укугу бар. 2. Соттук териштирүү ачык жана тараптардын атаандаштыгынын негизинде жүргүзүлөт.", ru: "1. Каждый имеет право на справедливое судебное разбирательство. 2. Судебное разбирательство проводится открыто и на основе состязательности сторон." } },
      { id: 64, title: { ky: "64-берене", ru: "Статья 64" }, content: { ky: "1. Адвокаттык ишмердүүлүктүн тартиби мыйзам менен белгиленет. 2. Адвокаттар юридикалык жардам көрсөтүүдө көз каранды эмес.", ru: "1. Порядок деятельности адвокатуры определяется законом. 2. Адвокаты независимы при оказании юридической помощи." } },
      { id: 65, title: { ky: "65-берене", ru: "Статья 65" }, content: { ky: "1. Соттордун чечимдери жогорку инстанцияларга шагымдалышы мүмкүн. 2. Ар бир адам соттун чечимин апелляциялык жана кассациялык тартипте шагымдоого укуктуу.", ru: "1. Решения судов могут быть обжалованы в вышестоящие инстанции. 2. Каждый имеет право обжаловать решение суда в апелляционном и кассационном порядке." } }
    ]
  },
  {
    title: { ky: "ҮЧҮНЧҮ БӨЛҮК. МАМЛЕКЕТТИК БИЙЛИКТИН ОРГАНДАРЫ", ru: "РАЗДЕЛ ТРЕТИЙ. ОРГАНЫ ГОСУДАРСТВЕННОЙ ВЛАСТИ" },
    articles: [
      { id: 66, title: { ky: "1-БАП. 66-берене", ru: "ГЛАВА I. Статья 66" }, content: { ky: "1. Президент мамлекеттин башчысы, жогорку кызмат адамы жана аткаруу бийлигин жетектейт. 2. Президент мамлекеттин ички жана тышкы саясатынын негизги багыттарын аныктайт.", ru: "1. Президент является главой государства, высшим должностным лицом и возглавляет исполнительную власть. 2. Президент определяет основные направления внутренней и внешней политики государства." } },
      { id: 67, title: { ky: "67-берене", ru: "Статья 67" }, content: { ky: "1. Президент Кыргыз Республикасынын жарандары тарабынан 5 жылдык мөөнөткө шайланат. 2. Президенттикке бир эле адам эки мөөнөттөн ашык шайлана албайт.", ru: "1. Президент избирается гражданами Кыргызской Республики сроком на 5 лет. 2. Одно и то же лицо не может быть избрано Президентом более двух сроков." } },
      { id: 68, title: { ky: "68-берене", ru: "Статья 68" }, content: { ky: "1. Президенттикке 35 жаштан кичүү эмес жана 70 жаштан чоң эмес жарананы шайлоого болот. 2. Президенттикке талапкер мамлекеттик тилди билүүгө тийиш.", ru: "1. Президентом может быть избран гражданин не моложе 35 лет и не старше 70 лет. 2. Кандидат в Президенты должен владеть государственным языком." } },
      { id: 69, title: { ky: "69-берене", ru: "Статья 69" }, content: { ky: "1. Кызматка киришкенде Президент Кыргызстан элине ант берет. 2. Ант Жогорку Кенештин алдында берилет.", ru: "1. При вступлении в должность Президент приносит присягу народу Кыргызстана. 2. Присяга приносится перед Жогорку Кенешем." } },
      { id: 70, title: { ky: "70-берене", ru: "Статья 70" }, content: { ky: "1. Президент Министрлер Кабинетинин түзүмүн аныктайт, Төраганы жана анын мүчөлөрүн дайындайт. 2. Президент Министрлер Кабинетинин Төрагасын Жогорку Кенештин макулдугу менен дайындайт.", ru: "1. Президент определяет структуру Кабинета Министров, назначает Председателя и его членов. 2. Президент назначает Председателя Кабинета Министров с согласия Жогорку Кенеша." } },
      { id: 71, title: { ky: "71-берене", ru: "Статья 71" }, content: { ky: "1. Президент өз ыйгарым укуктарын жарлыктарды жана тескемелерди кабыл алуу жолу менен ишке ашырат. 2. Президенттин жарлыктары жана тескемелери бүткүл аймакта милдеттүү.", ru: "1. Президент реализует свои полномочия путем принятия указов и распоряжений. 2. Указы и распоряжения Президента обязательны для исполнения на всей территории." } },
      { id: 72, title: { ky: "72-берене", ru: "Статья 72" }, content: { ky: "1. Президенттин ыйгарым укуктары анын кызматтан кетиши, ден соолугунун начарлашы же кайтыш болушу себептүү мөөнөтүнөн мурда токтотулушу мүмкүн. 2. Кызматтан кетүү жөнүндө арыз Президент тарабынан Жогорку Кенешке берилет.", ru: "1. Полномочия Президента могут быть прекращены досрочно в случае его отставки, стойкой неспособности по состоянию здоровья или смерти. 2. Заявление об отставке подается Президентом в Жогорку Кенеш." } },
      { id: 73, title: { ky: "73-берене", ru: "Статья 73" }, content: { ky: "1. Президент Жогорку Кенеш тарабынан айыптоо негизинде кызматтан четтетилиши мүмкүн. 2. Айыптоо Жогорку Кенештин депутаттарынын көпчүлүк добушу менен чыгарылат.", ru: "1. Президент может быть отрешен от должности Жогорку Кенешем на основании обвинения. 2. Обвинение выдвигается большинством голосов депутатов Жогорку Кенеша." } },
      { id: 74, title: { ky: "74-берене", ru: "Статья 74" }, content: { ky: "1. Президенттин ыйгарым укуктары мөөнөтүнөн мурда токтотулган учурда, анын милдетин Торага аткарат. 2. Торага ыйгарым укуктарды жаңы Президент шайланганга чейин аткарат.", ru: "1. В случае досрочного прекращения полномочий Президента их исполняет Торага. 2. Торага исполняет полномочия до избрания нового Президента." } },
      { id: 75, title: { ky: "75-берене", ru: "Статья 75" }, content: { ky: "1. Кызматтан четтетилгендерден башка бардык мурунку президенттер экс-президент статусуна ээ. 2. Экс-президенттерге мыйзамда белгиленген кепилдиктер берилет.", ru: "1. Все бывшие президенты, кроме отрешенных, имеют статус экс-президента. 2. Экс-президентам предоставляются гарантии, установленные законом." } },
      { id: 76, title: { ky: "2-БАП. 76-берене", ru: "ГЛАВА II. Статья 76" }, content: { ky: "1. Жогорку Кенеш - Кыргыз Республикасынын парламенти - жогорку өкүлчүлүк органы болуп саналат. 2. Жогорку Кенеш мыйзам чыгаруу бийлигин ишке ашырат.", ru: "1. Жогорку Кенеш - парламент Кыргызской Республики - является высшим представительным органом. 2. Жогорку Кенеш осуществляет законодательную власть." } },
      { id: 77, title: { ky: "77-берене", ru: "Статья 77" }, content: { ky: "1. Жогорку Кенеш 90 депутаттан турат жана 5 жылдык мөөнөткө шайланат. 2. Депутаттар партиялык тизмелер боюнча шайланат.", ru: "1. Жогорку Кенеш состоит из 90 депутатов и избирается сроком на 5 лет. 2. Депутаты избираются по партийным спискам." } },
      { id: 78, title: { ky: "78-берене", ru: "Статья 78" }, content: { ky: "1. Жогорку Кенештин депутаттыгына 25 жашка толгон жараны шайлана алат. 2. Депутаттыкка талапкер мамлекеттик тилди билүүгө тийиш.", ru: "1. Депутатом Жогорку Кенеша может быть избран гражданин, достигший 25 лет. 2. Кандидат в депутаты должен владеть государственным языком." } },
      { id: 79, title: { ky: "79-берене", ru: "Статья 79" }, content: { ky: "1. Жогорку Кенештин депутаты кол тийбестик укугуна ээ. 2. Депутатты анын макулдугусуз кармап калууга же күзөткө алууга болбойт.", ru: "1. Депутат Жогорку Кенеша имеет право неприкосновенности. 2. Депутат не может быть задержан или арестован без его согласия." } },
      { id: 80, title: { ky: "80-берене", ru: "Статья 80" }, content: { ky: "1. Жогорку Кенеш: мыйзамдарды кабыл алат, Конституцияга өзгөртүүлөрдү киргизет, бюджетти бекитет. 2. Жогорку Кенеш эл аралык келишимдерди ратификациялайт.", ru: "1. Жогорку Кенеш: принимает законы, вносит изменения в Конституцию, утверждает бюджет. 2. Жогорку Кенеш ратифицирует международные договоры." } },
      { id: 81, title: { ky: "81-берене", ru: "Статья 81" }, content: { ky: "1. Жогорку Кенеш өзүнүн курамынан Тораганы жана анын орун басарларын шайлайт. 2. Торага Жогорку Кенештин ишин уюштурат.", ru: "1. Жогорку Кенеш избирает из своего состава Торага Жогорку Кенеша и его заместителей. 2. Торага организует работу Жогорку Кенеша." } },
      { id: 82, title: { ky: "82-берене", ru: "Статья 82" }, content: { ky: "1. Жогорку Кенеш депутаттардын арасынан комитеттерди жана убактылуу комиссияларды түзөт. 2. Комитеттер мыйзам долбоорлорун даярдайт жана карайт.", ru: "1. Жогорку Кенеш образует из числа депутатов комитеты и временные комиссии. 2. Комитеты готовят и рассматривают законопроекты." } },
      { id: 83, title: { ky: "83-берене", ru: "Статья 83" }, content: { ky: "1. Жогорку Кенештин сессиялары сентябрдан июнга чейин жыйындар түрүндө өткөрүлөт. 2. Сессиялар ачык өткөрүлөт.", ru: "1. Сессии Жогорку Кенеша проводятся в форме заседаний с сентября по июнь. 2. Сессии проводятся открыто." } },
      { id: 84, title: { ky: "84-берене", ru: "Статья 84" }, content: { ky: "1. Жогорку Кенеш депутаттардын көпчүлүк добушу менен өзүн өзү таркатуу жөнүндө чечим кабыл алышы мүмкүн. 2. Өзүн өзү таркатуу мөөнөтүнөн мурда шайлоолорду дайындайт.", ru: "1. Жогорку Кенеш может принять решение о самороспуске большинством голосов. 2. Самороспуск назначает досрочные выборы." } },
      { id: 85, title: { ky: "85-берене", ru: "Статья 85" }, content: { ky: "1. Мыйзам чыгаруу демилгеси укугу төмөнкүлөргө таандык: 10 миң шайлоочуга, Президентке, депутаттарга. 2. Мыйзам чыгаруу демилгеси Кабинет Министрлерине да таандык.", ru: "1. Право законодательной инициативы принадлежит: 10 тысячам избирателей, Президенту, депутатам. 2. Право законодательной инициативы принадлежит также Кабинету Министров." } },
      { id: 86, title: { ky: "86-берене", ru: "Статья 86" }, content: { ky: "1. Мыйзам долбоорлору Жогорку Кенеш тарабынан, адатта, үч окууда каралат. 2. Ар бир окууда мыйзам долбоору талкууланып, түзөтүүлөр киргизилет.", ru: "1. Законопроекты рассматриваются Жогорку Кенешем, как правило, в трех чтениях. 2. В каждом чтении законопроект обсуждается и вносятся поправки." } },
      { id: 87, title: { ky: "87-берене", ru: "Статья 87" }, content: { ky: "1. Кабыл алынган мыйзам 14 күн ичинде кол коюу үчүн Президентке жөнөтүлөт. 2. Президент мыйзамга кол коюп же вето койо алат.", ru: "1. Принятый закон в течение 14 дней направляется Президенту для подписания. 2. Президент может подписать закон или наложить вето." } },
      { id: 88, title: { ky: "88-берене", ru: "Статья 88" }, content: { ky: "1. Мыйзам расмий жарыяланган күндөн тартып он күн өткөндөн кийин күчүнө кирет. 2. Мыйзам жарыяланган күндөн баштап күчүнө кириши мүмкүн.", ru: "1. Закон вступает в силу по истечении десяти дней со дня официального опубликования. 2. Закон может вступить в силу со дня опубликования." } },
      { id: 89, title: { ky: "3-БАП. 89-берене", ru: "ГЛАВА III. Статья 89" }, content: { ky: "1. Кыргыз Республикасында аткаруу бийлигин Президент жана Министрлер Кабинети ишке ашырат. 2. Аткаруу бийлиги мыйзамдардын аткарылышын уюштурат.", ru: "1. Исполнительную власть в Кыргызской Республике осуществляют Президент и Кабинет Министров. 2. Исполнительная власть организует исполнение законов." } },
      { id: 90, title: { ky: "90-берене", ru: "Статья 90" }, content: { ky: "1. Министрлер Кабинети Төрагадан, анын орун басарларынан жана мүчөлөрүнөн турат. 2. Министрлер Кабинетинин курамын Президент бекитет.", ru: "1. Кабинет Министров состоит из Председателя, заместителей и членов Кабинета Министров. 2. Состав Кабинета Министров утверждается Президентом." } },
      { id: 91, title: { ky: "91-берене", ru: "Статья 91" }, content: { ky: "1. Министрлер Кабинети Конституциянын, мыйзамдардын жана бюджеттин аткарылышын камсыз кылат. 2. Министрлер Кабинети өз иши жөнүндө Жогорку Кенешке отчет берет.", ru: "1. Кабинет Министров обеспечивает исполнение Конституции, законов и бюджета. 2. Кабинет Министров отчитывается перед Жогорку Кенешем о своей работе." } },
      { id: 92, title: { ky: "92-берене", ru: "Статья 92" }, content: { ky: "1. Президент өз демилгеси боюнча Министрлер Кабинетинин курамын отставкага жиберүүгө укуктуу. 2. Министрлер Кабинетинин Төрагасы да отставкага кете алат.", ru: "1. Президент по собственной инициативе вправе отправить Кабинет Министров в отставку. 2. Председатель Кабинета Министров также может уйти в отставку." } },
      { id: 93, title: { ky: "93-берене", ru: "Статья 93" }, content: { ky: "1. Жергиликтүү жерлерде аткаруу бийлигин мамлекеттик жергиликтүү администрация ишке ашырат. 2. Жергиликтүү администрациянын башчысын Президент дайындайт.", ru: "1. Исполнительную власть на местах осуществляет местная государственная администрация. 2. Глава местной администрации назначается Президентом." } },
      { id: 94, title: { ky: "4-БАП. 94-берене", ru: "ГЛАВА IV. Статья 94" }, content: { ky: "1. Кыргыз Республикасында сот адилеттигин сот гана ишке ашырат. 2. Соттор Конституцияга ылайык түзүлөт жана иш алып барат.", ru: "1. Правосудие в Кыргызской Республике осуществляется только судом. 2. Суды создаются и действуют в соответствии с Конституцией." } },
      { id: 95, title: { ky: "95-берене", ru: "Статья 95" }, content: { ky: "1. Соттор көз каранды эмес жана Конституцияга жана мыйзамдарга гана баш ийет. 2. Сот адилеттигин ишке ашырууда сотторго башка бийлик органдарынын кийлигишүүсүнө жол берилбейт.", ru: "1. Судьи независимы и подчиняются только Конституции и законам. 2. Вмешательство других органов власти в осуществление правосудия не допускается." } },
      { id: 96, title: { ky: "96-берене", ru: "Статья 96" }, content: { ky: "1. Бардык соттордун соттору өздөрүнүн жүрүм-туруму кемчиликсиз болгонго чейин кызматтарын ээлеп турушат. 2. Судьяларды кызматтан четтетүү мыйзамда каралган тартипте гана жүргүзүлөт.", ru: "1. Судьи всех судов занимают свои должности, пока их поведение является безупречным. 2. Отстранение судей от должности производится только в порядке, предусмотренном законом." } },
      { id: 97, title: { ky: "97-берене", ru: "Статья 97" }, content: { ky: "1. Конституциялык сот Конституцияны коргоо боюнча сот бийлигинин жогорку органы болуп саналат. 2. Конституциялык сот мыйзамдардын жана башка укуктук актылардын Конституцияга дал келишин текшерет.", ru: "1. Конституционный суд является высшим органом судебной власти по защите Конституции. 2. Конституционный суд проверяет соответствие законов и иных правовых актов Конституции." } },
      { id: 98, title: { ky: "98-берене", ru: "Статья 98" }, content: { ky: "1. Кыргыз Республикасынын Жогорку соту жалпы юрисдикциядагы соттордун тутумунда сот бийлигинин жогорку органы болуп саналат. 2. Жогорку сот апелляциялык жана кассациялык тартипте иштерди карайт.", ru: "1. Верховный суд Кыргызской Республики является высшим органом судебной власти в системе судов общей юрисдикции. 2. Верховный суд рассматривает дела в апелляционном и кассационном порядке." } },
      { id: 99, title: { ky: "99-берене", ru: "Статья 99" }, content: { ky: "1. Мамлекет соттордун иштеши үчүн каржылоону жана тийиштүү шарттарды камсыз кылат. 2. Сотторду каржылоо республикалык бюджеттен жүргүзүлөт.", ru: "1. Государство обеспечивает финансирование и надлежащие условия для функционирования судов. 2. Финансирование судов осуществляется из республиканского бюджета." } },
      { id: 100, title: { ky: "100-берене", ru: "Статья 100" }, content: { ky: "1. Бардык соттордо иштерди кароо ачык жүргүзүлөт. 2. Иштерди жабык отурумда кароого мыйзамда каралган учурларда гана жол берилет.", ru: "1. Разбирательство дел во всех судах осуществляется открыто. 2. Рассмотрение дел в закрытом заседании допускается только в случаях, предусмотренных законом." } },
      { id: 101, title: { ky: "101-берене", ru: "Статья 101" }, content: { ky: "1. Соттордун мыйзамдуу күчүнө кирген чечимдери бардык жарандар жана органдар үчүн милдеттүү. 2. Соттун чечимин аткарбаган адамдар мыйзам боюнча жоопко тартылат.", ru: "1. Вступившие в законную силу решения судов обязательны для всех граждан и органов. 2. Лица, не исполняющие решение суда, привлекаются к ответственности по закону." } },
      { id: 102, title: { ky: "102-берене", ru: "Статья 102" }, content: { ky: "1. Сот Конституцияга каршы келген ченемдик укуктук актыны колдонууга укуктуу эмес. 2. Сот түздөн-түз Конституциянын ченемдерин колдоно алат.", ru: "1. Суд не вправе применять нормативный правовой акт, противоречащий Конституции. 2. Суд может применять непосредственно нормы Конституции." } },
      { id: 103, title: { ky: "103-берене", ru: "Статья 103" }, content: { ky: "1. Соттордун ички иштерин чечүү үчүн соттук өзүн-өзү башкаруу иштейт. 2. Соттордун өзүн-өзү башкаруу органдары соттордун көз каранды эместигин камсыз кылат.", ru: "1. Для решения вопросов внутренней деятельности судов действует судейское самоуправление. 2. Органы судейского самоуправления обеспечивают независимость судов." } },
      { id: 104, title: { ky: "104-берене", ru: "Статья 104" }, content: { ky: "1. Мыйзамда каралган учурларда сот адилеттиги акысыз ишке ашырылат. 2. Кедей жана муктаж адамдарга соттук чыгымдарды төлөөдөн бошотуу берилиши мүмкүн.", ru: "1. Правосудие отправляется бесплатно в предусмотренных законом случаях. 2. Малоимущим и нуждающимся лицам может быть предоставлено освобождение от уплаты судебных расходов." } },
      { id: 105, title: { ky: "5-БАП. 105-берене", ru: "ГЛАВА V. Статья 105" }, content: { ky: "1. Мыйзамдардын так жана бирдей аткарылышын көзөмөлдөө прокуратура тарабынан ишке ашырылат. 2. Прокурорлор мамлекеттин атынан көзөмөлдү ишке ашырышат.", ru: "1. Надзор за точным и единообразным исполнением законов осуществляется прокуратурой. 2. Прокуроры осуществляют надзор от имени государства." } },
      { id: 106, title: { ky: "106-берене", ru: "Статья 106" }, content: { ky: "1. Улуттук банк банктык тутумду жана акча-кредит саясатын көзөмөлдөйт. 2. Улуттук банк улуттук валютаны чыгарат.", ru: "1. Национальный банк осуществляет надзор за банковской системой и денежно-кредитной политикой. 2. Национальный банк осуществляет эмиссию национальной валюты." } },
      { id: 107, title: { ky: "107-берене", ru: "Статья 107" }, content: { ky: "1. Борбордук шайлоо комиссиясы шайлоолорду даярдоону жана өткөрүүнү камсыз кылат. 2. Борбордук шайлоо комиссиясынын курамын Жогорку Кенеш түзөт.", ru: "1. Центральная комиссия по выборам обеспечивает подготовку и проведение выборов. 2. Состав Центральной комиссии по выборам формируется Жогорку Кенешем." } },
      { id: 108, title: { ky: "108-берене", ru: "Статья 108" }, content: { ky: "1. Эсеп палатасы республикалык жана жергиликтүү бюджеттердин аткарылышына аудит жүргүзөт. 2. Эсеп палатасы Жогорку Кенешке отчет берет.", ru: "1. Счетная палата осуществляет аудит исполнения республиканского и местных бюджетов. 2. Счетная палата отчитывается перед Жогорку Кенешем." } },
      { id: 109, title: { ky: "109-берене", ru: "Статья 109" }, content: { ky: "1. Адамдын укуктарынын сакталышын көзөмөлдөө Акыйкатчы (Омбудсмен) тарабынан ишке ашырылат. 2. Акыйкатчы адамдын укуктары бузулган учурда аларды калыбына келтирүү боюнча чараларды көрөт.", ru: "1. Контроль за соблюдением прав человека осуществляется Акыйкатчы (Омбудсменом). 2. Акыйкатчы принимает меры по восстановлению нарушенных прав человека." } },
      { id: 110, title: { ky: "110-берене", ru: "Статья 110" }, content: { ky: "1. Өзгөчө статусу бар органдардын ишмердүүлүгүн уюштуруу жана тартиби мыйзамдар менен аныкталат. 2. Мындай органдардын ыйгарым укуктары мыйзамда көрсөтүлөт.", ru: "1. Организация и порядок деятельности органов со специальным статусом определяются законами. 2. Полномочия таких органов указываются в законе." } }
    ]
  },
  {
    title: { ky: "ТӨРТҮНЧҮ БӨЛҮК. ЖЕРГИЛИКТҮҮ ӨЗҮН-ӨЗҮ БАШКАРУУ", ru: "РАЗДЕЛ ЧЕТВЕРТЫЙ. МЕСТНОЕ САМОУПРАВЛЕНИЕ" },
    articles: [
      { id: 111, title: { ky: "111-берене", ru: "Статья 111" }, content: { ky: "1. Жергиликтүү өзүн-өзү башкаруу - бул коомдоштуктардын жергиликтүү маанидеги маселелерди чечүүгө кепилденген укугу. 2. Жергиликтүү өзүн-өзү башкаруу мамлекеттик бийлик тутумуна кирбейт.", ru: "1. Местное самоуправление - гарантированное право сообществ решать вопросы местного значения. 2. Местное самоуправление не входит в систему государственной власти." } },
      { id: 112, title: { ky: "112-берене", ru: "Статья 112" }, content: { ky: "1. Жергиликтүү өзүн-өзү башкаруу органдары өкүлчүлүк жана аткаруу органдарынан турат. 2. Өкүлчүлүк органы - жергиликтүү кеңеш, аткаруу органы - мэрия.", ru: "1. Органы местного самоуправления состоят из представительных и исполнительных органов. 2. Представительный орган - местный кенеш, исполнительный орган - мэрия." } },
      { id: 113, title: { ky: "113-берене", ru: "Статья 113" }, content: { ky: "1. Жергиликтүү кеңештердин депутаттары ушул бирдикте жашаган жарандар тарабынан шайланат. 2. Депутаттардын ыйгарым укуктарынын мөөнөтү 5 жылды түзөт.", ru: "1. Депутаты местных кенешей избираются гражданами, проживающими в данной единице. 2. Срок полномочий депутатов составляет 5 лет." } },
      { id: 114, title: { ky: "114-берене", ru: "Статья 114" }, content: { ky: "1. Мамлекеттик органдардын МСУнун ыйгарым укуктарына кийлигишүүгө укугу жок. 2. МСУнун чечимдери мамлекеттик органдардын чечимдери менен күчүн жоготушу мүмкүн, эгерде алар мыйзамга каршы келсе.", ru: "1. Государственные органы не вправе вмешиваться в полномочия органов МСУ. 2. Решения МСУ могут быть отменены государственными органами, если они противоречат закону." } },
      { id: 115, title: { ky: "115-берене", ru: "Статья 115" }, content: { ky: "1. Жарандар тараптарды элдештирүү үчүн аксакалдар сотун түзүүгө укуктуу. 2. Аксакалдар соту жергиликтүү салттардын негизинде иш алып барат.", ru: "1. Граждане имеют право учреждать суды аксакалов для примирения сторон. 2. Суд аксакалов действует на основе местных традиций." } }
    ]
  },
  {
    title: { ky: "БЕШИНЧИ БӨЛҮК. КОНСТИТУЦИЯГА ӨЗГӨРТҮҮЛӨРДҮ КИРГИЗҮҮ ТАРТИБИ", ru: "РАЗДЕЛ ПЯТЫЙ. ПОРЯДОК ИЗМЕНЕНИЙ В КОНСТИТУЦИЮ" },
    articles: [
      { id: 116, title: { ky: "116-берене", ru: "Статья 116" }, content: { ky: "1. Конституция 300 миң шайлоочунун же Президенттин демилгеси боюнча кабыл алынышы мүмкүн. 2. Конституцияга өзгөртүүлөр референдумда кабыл алынат. 3. Конституциянын 1-бөлүгүнүн 1-12-статьяларына өзгөртүүлөрдү киргизүүгө жол берилбейт.", ru: "1. Конституция может быть принята по инициативе 300 тысяч избирателей или Президента. 2. Изменения в Конституцию принимаются на референдуме. 3. Изменения в статьи 1-12 раздела 1 Конституции не допускаются." } }
    ]
  }
];



const Constitution = () => {
  const [lang, setLang] = useState('ky'); 
  const [searchTerm, setSearchTerm] = useState('');
  const [openSection, setOpenSection] = useState(0);
  const [selectedArticle, setSelectedArticle] = useState(null);

  // 1. Издөө жана чыпкалоо логикасы (коопсуздук үчүн ?. белгиси кошулду)
  const filteredSections = (constitutionData || []).map(section => {
    const matched = (section.articles || []).filter(art => {
      const titleText = art.title?.[lang] || "";
      const contentText = art.content?.[lang] || "";
      return (
        titleText.toLowerCase().includes(searchTerm.toLowerCase()) ||
        contentText.toLowerCase().includes(searchTerm.toLowerCase())
      );
    });
    return { ...section, articles: matched };
  }).filter(section => section.articles.length > 0);

  // 2. Биринчи жолу ачылганда биринчи статьяны таап алуу
  useEffect(() => {
    if (!selectedArticle && constitutionData && constitutionData.length > 0) {
      if (constitutionData[0].articles && constitutionData[0].articles.length > 0) {
        setSelectedArticle(constitutionData[0].articles[0]);
      }
    }
  }, [selectedArticle]);

  return (
    <div className="constitution-wrapper">
      <div className="article-sidebar">
        
        {/* ТИЛ АЛМАШТЫРГЫЧ (ky жана ru) */}
        <div className="language-switcher">
          <button 
            className={lang === 'ky' ? 'active-lang' : ''} 
            onClick={() => setLang('ky')}
          >KG</button>
          <button 
            className={lang === 'ru' ? 'active-lang' : ''} 
            onClick={() => setLang('ru')}
          >RU</button>
        </div>

        {/* ИЗДӨӨ */}
        <div className="search-box-container">
          <input
            className="search-input"
            type="text"
            placeholder={lang === 'ky' ? "Издөө..." : "Поиск..."}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {/* ТИЗМЕ (АККОРДЕОН) */}
        <div className="article-list">
          {filteredSections.map((section, sIndex) => (
            <div key={sIndex} className="accordion-group">
              <div 
                className={`accordion-title ${openSection === sIndex ? 'active' : ''}`}
                onClick={() => setOpenSection(openSection === sIndex ? null : sIndex)}
              >
                <span>{section.title?.[lang]}</span>
                <span className="arrow">{openSection === sIndex ? '−' : '+'}</span>
              </div>
              
              <div className={`accordion-content ${openSection === sIndex ? 'show' : ''}`}>
                {section.articles.map((art) => (
                  <div 
                    key={art.id} 
                    className={`sub-article-item ${selectedArticle?.id === art.id ? 'selected' : ''}`}
                    onClick={() => setSelectedArticle(art)}
                  >
                    {art.title?.[lang]}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ОҢ ТАРАП (НЕГИЗГИ ТЕКСТ) */}
      <div className="article-content">
        {selectedArticle ? (
          <div className="content-card">
            <h1 className="active-title-name">{selectedArticle.title?.[lang]}</h1>
            <div className="accent-line"></div>
            <p className="content-text" style={{ whiteSpace: 'pre-wrap' }}>
              {selectedArticle.content?.[lang]}
            </p>
          </div>
        ) : (
          <div style={{ textAlign: 'center', marginTop: '50px', color: '#999' }}>
            {lang === 'ky' ? "Маалымат жүктөлүүдө..." : "Загрузка данных..."}
          </div>
        )}
      </div>
    </div>
  );
};

export default Constitution;